const items = $input.all();

// Ignore les emails automatiques
const skipKeywords = ['noreply', 'no-reply', 'newsletter', 'unsubscribe', 'notification', 'mailer-daemon'];

const emails = items
  .map(item => item.json)
  .filter(email => {
    const from = email.from || '';
    const subject = email.subject || '';
    return !skipKeywords.some(k => 
      from.toLowerCase().includes(k) || 
      subject.toLowerCase().includes(k)
    );
  })
  .map(email => ({
    from: email.from || 'Inconnu',
    subject: email.subject || '(Sans sujet)',
    snippet: email.snippet || email.text?.substring(0, 200) || '',
    date: email.internalDate 
      ? new Date(parseInt(email.internalDate)).toLocaleString('fr-FR', {day:'2-digit', month:'2-digit', hour:'2-digit', minute:'2-digit'})
      : ''
  }));

// Formate pour l'IA
const emailList = emails.map((e, i) => 
  `Email ${i+1}:\nDe: ${e.from}\nSujet: ${e.subject}\nDate: ${e.date}\nAperçu: ${e.snippet}`
).join('\n\n---\n\n');

const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000)
  .toLocaleDateString('fr-FR', {day:'2-digit', month:'long'});
const weekEnd = new Date().toLocaleDateString('fr-FR', {day:'2-digit', month:'long', year:'numeric'});

return [{
  json: {
    emailList,
    totalEmails: emails.length,
    weekRange: `${weekStart} - ${weekEnd}`
  }
}];

const input = $input.item.json;
const stats = $('Préparer les emails').item.json;

const digest = 
  input?.content?.[0]?.text ||
  input?.text ||
  input?.choices?.[0]?.message?.content ||
  'Digest non disponible';

const today = new Date().toLocaleDateString('fr-FR', {
  weekday: 'long', day: '2-digit', month: 'long', year: 'numeric'
});

return [{
  json: {
    to: 'saadmehamdi2018@gmail.com',
    subject: `📬 Ton digest Gmail — Semaine du ${stats.weekRange}`,
    body: `Bonjour Saad ! 👋\n\nVoici ton résumé hebdomadaire Gmail généré le ${today}.\n${stats.totalEmails} emails analysés cette semaine.\n\n${'═'.repeat(50)}\n\n${digest}\n\n${'═'.repeat(50)}\n\nBonne semaine ! 🚀\n— Ton assistant IA n8n`
  }
}];
